$startIteration = 501

for ($i = 0; $i -lt 200; $i++) {
    $iteration = $startIteration + $i
    $typeIndex = $i % $commitTypes.Count
    $commitType = $commitTypes[$typeIndex]
    $itemIndex = $i % $commitType.items.Count
    $item = $commitType.items[$itemIndex]
    
    $fileName = "src/features/feature_$iteration.ts"
    $content = @"
// Feature $iteration - $item
export const feature$iteration = {
  name: '$item',
  enabled: true,
  version: '$iteration.0.0',
  timestamp: $([DateTimeOffset]::UtcNow.ToUnixTimeSeconds()),
};
"@
    
    New-Item -Path $fileName -ItemType File -Force | Out-Null
    Set-Content -Path $fileName -Value $content
    
    git add .
    git commit -m "$($commitType.type): $($commitType.desc) $item (iteration $iteration)" --quiet
    
    if ($i % 50 -eq 0) {
        Write-Host "Progress: $i/200 commits"
    }
}

Write-Host "Completed 200 commits!"
